import { Button, ModalR, RenderTitle, Spinner, MultiselectWithSearchR } from '../../../common';
import { useCallback, useEffect, useState } from 'react';
import cls from './WorkflowTemplatesModal.module.scss';
import Select from 'react-select';
import { connect } from 'react-redux';
import { createNewProcess, createProcessTemplate, getProcessById, shareProcessToSeveralPositions, updatingProcessById } from '../../../../services/processes.service';
import { setMessageBar, setSelectedProcess, setShowMenu, setShowSideMenu } from '../../../../reduxStore/actions/flowActions';
import { store } from '../../../../reduxStore/store';
import { isMobile, isSafari } from 'react-device-detect';

import MessageContainer from '../../ProcessesComps/MessageContainer/MessageContainer';
import { first, tap } from 'rxjs';
import { useNavigate } from 'react-router-dom';
import Loader from 'react-loader-spinner';


const WorkflowTemplatesModal = props => {
	const { isOpen, shadowedContainerStyle, onCreateBlank, gotoProcess, workflowTemplates, gotoComponents } = props;
	const [error, setError] = useState('');
	const [loading, setLoading] = useState(false);
	document.title = 'New Workflow';

	const navigate = useNavigate();

	const renderWorkflows = () => {
		return workflowTemplates?.map((process, index) => (
			<div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '200px' }} key={index}>
				<p className={cls.trialTitle}>{`Templates`}</p>
				<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
				<div className={cls.header} >
					<p className={cls.trialText}>{`${process.name}`}</p>
					<Button
						disabled={loading}
						title={`Use`}
						style={{ backgroundColor: 'rgb(83, 159, 234)', width: '140px', minWidth: '80px' }}
						clicked={() => {
							setLoading(true);
							createProcessTemplate(process).pipe(first()).subscribe({
								next: data => {
									setLoading(false);
									gotoProcess(data);
								},
								error: error => {
									console.log('error', error)
									setLoading(false);
								}
							})
						}}
					/>
				</div>
				<br /><br />
				<p className={cls.subTitle}>{`${process.description}`}</p>
			</div>
		));
	};


	const blankWorkflow = () => {
		return <div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '200px' }} >
			<p className={cls.trialTitle}>{`New`}</p>
			<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
			<div className={cls.header}>
				<p className={cls.trialText}>{`Blank Workflow`}</p>
				<Button
					disabled={loading}
					title={`Create`}
					style={{ width: '140px', minWidth: '80px' }}
					clicked={onCreateBlank}
				/>
			</div>
			<br />
			<br />
			<p className={cls.subTitle}>{`Create your workflow using a blank canvass`}</p>
		</div>
			;
	};
	const createComponents = () => {
		return <div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%', minWidth: '200px' }} >
			<p className={cls.trialTitle}>{`Components`}</p>
			<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
			<div className={cls.header}>
				<p className={cls.trialText}>{`Create Components`}</p>
				<Button
					disabled={loading}
					title={`Create`}
					style={{ width: '140px', minWidth: '80px' }}
					clicked={gotoComponents}
				/>
			</div>
			<br />
			<br />
			<p className={cls.subTitle}>{`Components are objects that workflows use to input or output informations. In forms they are usally called fields.`}</p>
		</div>
			;
	};
	return (
		<ModalR isOpen={isOpen} blured={true} scrollable={true} shadowedContainerStyle={shadowedContainerStyle}>
			<div className={cls.host}>


				<div style={{ display: 'flex', alignItems: 'center' }}>
					<p className={cls.title}>
						{'New Workflow'}
					</p>
					<Button clear loading={loading} />
				</div>

				<p className={cls.subtitle} >
					{'Start a new workflow or select from any of our predefined templates'}
				</p>

				{blankWorkflow()}
				{renderWorkflows()}
				{createComponents()}

			</div>
			<div className={cls.controls}>
				<Button disabled={loading} loading={loading} title={'Close'} clicked={() => navigate('/')} />


			</div>

		</ModalR>
	);
};

const mapStateToProps = store => {
	const { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted, workflowTemplates } = store.flowReducer;
	return { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted, workflowTemplates };
};

export default connect(mapStateToProps)(WorkflowTemplatesModal);
